const path = require('path');
const body = $input.item.json.body || $input.item.json;
const listingId = body.listing_id;
const baseDir = process.env.FRAMES_BASE_PATH || '/data/frames';
const outDir = process.env.VIDEOS_BASE_PATH || '/data/videos';
const framesPath = path.join(baseDir, String(listingId));
const outPath = path.join(outDir, listingId + '.mp4');
const fps = body.fps || 25;
return [{ json: { listing_id: listingId, frames_path: framesPath, out_path: outPath, fps } }];
